UPDATE spells SET summary = 'Summon fey spirits in form of beasts (CR 2 or lower, or 2/4/8 of lower CR). They''re friendly, obey verbal commands, and disappear at 0 HP or spell end.''' WHERE slug = 'conjure-animals';
