UPDATE spells SET summary = 'Spirits flit around you. Attacks within 10 feet deal {@damage 1d8} extra radiant/necrotic/cold damage (your choice). Targets can''t regain HP until next turn''s start. Creatures within 10 feet: speed -10 feet.''' WHERE slug = 'spirit-shroud';
