UPDATE spells SET summary = 'Call shadow spirit using Shadow Spirit stat block. Choose emotion: Fury, Despair, or Fear. Ally sharing initiative, obeys verbal commands. Disappears at 0 HP or spell end.''' WHERE slug = 'summon-shadowspawn';
